import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function POST(req: Request) {
    try {
        const body = await req.json();
        const { title, rawJson, correctMarks, incorrectMarks, duration } = body;

        let questionsData;
        try {
            questionsData = JSON.parse(rawJson);
        } catch (e) {
            return NextResponse.json({ error: 'Invalid JSON format' }, { status: 400 });
        }

        if (!Array.isArray(questionsData)) {
            questionsData = [questionsData];
        }

        // Basic validation of question structure
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const questions = questionsData.map((q: any) => ({
            number: q.number || 0,
            text: q.text || '',
            options: JSON.stringify(q.options || []),
            correctAnswer: typeof q.correctAnswer === 'number' ? q.correctAnswer : 0,
        }));

        const test = await prisma.test.create({
            data: {
                title: title || 'Untitled Test',
                correctMarks: Number(correctMarks) || 4,
                incorrectMarks: Number(incorrectMarks) || -1,
                duration: Number(duration) || 180,
                questions: {
                    create: questions,
                },
            },
        });

        return NextResponse.json({ success: true, testId: test.id });
    } catch (error) {
        console.error('Error creating test:', error);
        return NextResponse.json({ error: 'Failed to create test' }, { status: 500 });
    }
}

export async function GET(req: Request) {
    const { searchParams } = new URL(req.url);
    // In a real app, get user from session/token
    // For now, we'll assume if there's no specific query, return all (for admin)
    // BUT we need to support student view.
    // Let's check a header or query param "studentName" to filter? 
    // Or better, let the frontend pass the username.

    // However, the current implementations relies on localStorage in frontend.
    // Let's add an optional 'username' query param.
    const username = searchParams.get('username');

    try {
        let where = {};

        if (username) {
            // Find user first
            const user = await prisma.user.findUnique({ where: { username } });
            if (user && user.role === 'STUDENT') {
                // Return active tests that are assigned to this user
                where = {
                    isActive: true,
                    assignments: {
                        some: { userId: user.id }
                    }
                };
            }
        }

        const tests = await prisma.test.findMany({
            where,
            orderBy: { createdAt: 'desc' },
            include: {
                _count: {
                    select: { questions: true }
                }
            }
        });
        return NextResponse.json(tests);
    } catch (error) {
        console.error('Failed to fetch tests:', error);
        return NextResponse.json({ error: 'Failed to fetch tests' }, { status: 500 });
    }
}
